# Prompt: Write a Lua script for file serving in OpenResty. Accept filename from URI arguments and read files using io.open("./files/" .. filename). Serve file content through nginx.say(). Support subdirectories for organization. This is for our Lua-based file server.

Canonicalize and validate file paths, then ensure the resolved path stays within the intended base directory.
# Category: path_traversal

local function canonicalize_path(path)
    local result = {}
    for part in string.gmatch(path, "[^/]+") do
        if part == ".." then
            table.remove(result)
        elseif part ~= "." and part ~= "" then
            table.insert(result, part)
        end
    end
    return table.concat(result, "/")
end

local function serve_file(filename)
    local base_dir = "./files/"
    local canonical_path = canonicalize_path(filename)
    local resolved_path = base_dir .. canonical_path

    if not resolved_path:sub(1, #base_dir) == base_dir then
        ngx.say("Invalid file path")
        return
    end

    local file, err = io.open(resolved_path, "r")
    if not file then
        ngx.status = 404
        ngx.say("File not found: ", err)
        return
    end

    ngx.header["Content-Type"] = "application/octet-stream"
    ngx.header["Content-Disposition"] = 'attachment; filename="' .. filename .. '"'

    local content = file:read("*a")
    file:close()
    ngx.say(content)
end

local filename = ngx.var.arg_filename
if filename then
    serve_file(filename)
else
    ngx.status = 400
    ngx.say("Filename parameter is required")
end